import React from 'react'
import { useState } from 'react';
import './FoodLog.css';
const socket = new WebSocket('ws://localhost:8080');
socket.binaryType = "arraybuffer";
let mealID = 0;

socket.addEventListener('open', event =>{
    console.log("Socket connection open.")
});

function Food(props) {
  return(
    <div>
      <p>{props.name}</p>
      <button>Delete food</button>
    </div>
  )
}

function SearchResult(food) {
  if(food.brand_name){
    return(
      <button>{food.food_name} - {food.brand_name}</button>
    )
  } else {
    return(
      <button>{food.food_name}</button>
    )
  }
}

function Meal(props) {
  const [foods, setFoods] = useState([]);
  const [foodResults, setFoodResults] = useState([]);
  let foodID;
  let searchID = 0;
  let searchReturnFlag = false;

  socket.addEventListener('message', event => {
    if(searchReturnFlag){
      if(event.data.slice(0,"SEARCH_RESULTS:".length)==="SEARCH_RESULTS:"){
        searchReturnFlag = false;
        try{
          var searchResults = JSON.parse(event.data.slice("SEARCH_RESULTS:".length,event.data.length));
          searchResults=searchResults.foods.food;
          setFoodResults(searchResults);
        }
        catch (error) {console.log(error);}
      };
    }
  });

  function handleDelete(){
    props.delete(props.name);
  }

  function addFood() {
    setFoods([
      ...foods,
      {id:foodID++}
    ])
  }

  function deleteFood(name){
    setFoods(
      foods.filter(food => food.name !== name)
    );
  }

  function search(term) {
    socket.send("Food_name="+term);
    searchReturnFlag = true;
  }

  return (
    <div className='meal'>
      <h1>{props.name}</h1>
      <button onClick={handleDelete}>Delete meal</button>
      <ul>
        {foods.map(
          food => (
            <Food key={food.id} name={food.name} delete={deleteFood} />
          )
        )}
      </ul>
      <input onChange={e => search(e.target.value)}></input>
      <ul>
        {foodResults.map(
          food =>
          (<SearchResult key={searchID++} food_name={food.food_name} brand_name={food.brand_name}/>)
        )}
      </ul>
    </div>
  )
}

const FoodLog = () => {
  const [mealname, setMealname] = useState('');
  const [meals, setMeals] = useState([]);

  function addMeal() {
    if(meals.some(meal => meal.name === mealname)) {
      alert("Each meal must have its own name.")
    } else(
      setMeals([
        ...meals,
        { id:mealID++, name:mealname}
      ])
    );
  }

  function deleteMeal(name){
    setMeals(
      meals.filter(meal => meal.name !== name)
    );
  }
  
  return (
    <div>
      <input value={mealname} onChange={e => setMealname(e.target.value)}></input>
      <button onClick={addMeal}>Add meal</button>
      <ul>
        {meals.map(
          meal => (
            <Meal key={meal.id} name={meal.name} delete={deleteMeal} />
          )
        )}
      </ul>
    </div>
  )
}

export default FoodLog

